<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    buildSlurmForRedHatBased</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 编译Slurm</span></span>
